    def trust_level(self) -> str:
        if not self.verification_valid:
            return 'UNTRUSTED'
        if self.assumptions_used:
            return 'CONDITIONAL'
        if self.z3_calls > 0:
            return 'Z3_PROVEN'
        return 'STRUCTURALLY_VERIFIED'


