# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.extraction.verified","kind":"function","src_hash":"4f9becedca0192e3","in":{"base":"ProofTerm"},"out":{"base":"Callable"},"spec":{"lhs":"verified(pro)","rhs":"decorator that attaches a verification certificate to a function","over":{"base":"ProofTerm"},"name":"verified_correct"},"guarantee":"decorator that attaches a verification certificate to a function","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.extraction.verified_correct","statement":"Path(verified(x), decorator that attaches a verification certificate to a function)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"038a1076d53fa952"}
def verified(
    proof: ProofTerm,
    lhs: OTerm,
    rhs: OTerm,
    ctx: Optional[ProofContext] = None,
) -> Callable:
    """Decorator that attaches a verification certificate to a function.

    Usage::

        @verified(CORRECTNESS_PROOF, IMPL_OTERM, SPEC_OTERM)
        def my_function(n):
            ...

    The decorated function gains attributes:
      - _c4_certificate: ExtractionCertificate
      - _c4_verified: bool
      - _c4_proof_strategy: str
    """
    result = check_proof(proof, lhs, rhs, ctx)
    cert = ExtractionCertificate(
        proof_strategy=type(proof).__name__,
        lhs_description=lhs.canon() if hasattr(lhs, 'canon') else str(lhs),
        rhs_description=rhs.canon() if hasattr(rhs, 'canon') else str(rhs),
        verification_valid=result.valid,
        assumptions_used=result.assumptions,
        z3_calls=result.z3_calls,
        proof_depth=result.proof_depth,
    )

    def decorator(fn: Callable) -> Callable:
        fn._c4_certificate = cert  # type: ignore[attr-defined]
        fn._c4_verified = result.valid  # type: ignore[attr-defined]
        fn._c4_proof_strategy = type(proof).__name__  # type: ignore[attr-defined]
        return fn

    return decorator


